class Solution {
public:
    vector<long long> maximumEvenSplit(long long finalSum) {
        if (finalSum % 2 != 0) return {};
        vector<long long> result;
        long long i = 2;
        while (finalSum > 0) {
            if (finalSum >= i) {
                result.push_back(i);
                finalSum -= i;
                i += 2;
            } else {
                break;
            }
        }
        if (finalSum > 0) {
            result.back() += finalSum;
            finalSum = 0;
        }
        return result;
    }
};
```

